/*
 * Operating System Design: Mechanism vs Policy Separation
 * Implementation in C - Demonstrates how the same mechanism
 * can support different scheduling policies
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Maximum number of processes */
#define MAX_PROCESSES 10

/* Process control block (PCB) */
typedef struct {
 int pid;
 char name[32];
 int priority; /* Lower number = higher priority */
 int burst_time;
 int remaining_time;
 int arrival_time;
} Process;

/* Scheduling policy function pointer - THIS IS THE KEY!
 * This allows different policies to be plugged in */
typedef int (*PolicySelector)(Process queue[], int count);

/* Scheduler mechanism - handles the FIXED parts of scheduling */
typedef struct {
 Process ready_queue[MAX_PROCESSES];
 int queue_count;
 PolicySelector policy; /* Plug-in policy function */
 const char *policy_name;
} Scheduler;

/* ============================================================
 * MECHANISM: These functions implement the FIXED scheduling
 * framework that doesn't change regardless of policy
 * ============================================================
 */

void init_scheduler(Scheduler *sched, PolicySelector policy, const char *name) {
 sched->queue_count = 0;
 sched->policy = policy;
 sched->policy_name = name;
}

void add_process(Scheduler *sched, Process p) {
 if (sched->queue_count < MAX_PROCESSES) {
 sched->ready_queue[sched->queue_count++] = p;
 printf("[MECHANISM] Process %d (%s) added to ready queue\n", p.pid, p.name);
 }
}

/* This is the MECHANISM - it calls the policy but doesn't know
 * which policy is being used. This is the separation point! */
Process* dispatch(Scheduler *sched) {
 if (sched->queue_count == 0 || sched->policy == NULL) {
 return NULL;
 }

 /* MECHANISM: Ask POLICY to select next process */
 int selected_index = sched->policy(sched->ready_queue, sched->queue_count);

 printf("[MECHANISM] Dispatching process %d using %s policy\n",
 sched->ready_queue[selected_index].pid, sched->policy_name);

 /* Remove selected process from queue */
 Process *selected = malloc(sizeof(Process));
 *selected = sched->ready_queue[selected_index];

 /* Shift remaining processes */
 for (int i = selected_index; i < sched->queue_count - 1; i++) {
 sched->ready_queue[i] = sched->ready_queue[i + 1];
 }
 sched->queue_count--;

 return selected;
}

/* ============================================================
 * POLICIES: These are the SWAPPABLE decision rules
 * Changing policy doesn't affect the mechanism
 * ============================================================
 */

/* POLICY: First Come First Served */
int policy_fcfs(Process queue[], int count) {
 /* Select first process (FIFO order) */
 return 0;
}

/* POLICY: Priority Scheduling */
int policy_priority(Process queue[], int count) {
 int highest_priority_index = 0;

 for (int i = 1; i < count; i++) {
 if (queue[i].priority < queue[highest_priority_index].priority) {
 highest_priority_index = i;
 }
 }

 return highest_priority_index;
}

/* POLICY: Shortest Job First */
int policy_sjf(Process queue[], int count) {
 int shortest_index = 0;

 for (int i = 1; i < count; i++) {
 if (queue[i].burst_time < queue[shortest_index].burst_time) {
 shortest_index = i;
 }
 }

 return shortest_index;
}

/* ============================================================
 * Main demonstration
 * ============================================================
 */

int main() {
 /* Create sample processes */
 Process processes[] = {
 {1, "Chrome", 3, 10, 10, 0},
 {2, "VS Code", 1, 5, 5, 0}, /* Highest priority */
 {3, "Spotify", 2, 8, 8, 0}
 };

 printf("======================================================\n");
 printf("OS Design Principle: Mechanism vs Policy Separation\n");
 printf("======================================================\n\n");

 /* DEMONSTRATION 1: FCFS Policy */
 printf("--- DEMO 1: Using FCFS Policy ---\n");
 Scheduler sched_fcfs;
 init_scheduler(&sched_fcfs, policy_fcfs, "FCFS");

 for (int i = 0; i < 3; i++) {
 add_process(&sched_fcfs, processes[i]);
 }

 Process *p;
 while ((p = dispatch(&sched_fcfs)) != NULL) {
 printf(" Running process %d (%s) for %d time units\n\n",
 p->pid, p->name, p->burst_time);
 free(p);
 }

 /* DEMONSTRATION 2: Priority Policy - SAME MECHANISM! */
 printf("--- DEMO 2: Using Priority Policy (SAME MECHANISM!) ---\n");
 Scheduler sched_priority;
 init_scheduler(&sched_priority, policy_priority, "Priority");

 for (int i = 0; i < 3; i++) {
 add_process(&sched_priority, processes[i]);
 }

 while ((p = dispatch(&sched_priority)) != NULL) {
 printf(" Running process %d (%s) with priority %d\n\n",
 p->pid, p->name, p->priority);
 free(p);
 }

 printf("======================================================\n");
 printf("KEY INSIGHT:\n");
 printf("We used the SAME Scheduler mechanism (init_scheduler,\n");
 printf("add_process, dispatch) but changed the POLICY function\n");
 printf("pointer to get different scheduling behaviors!\n");
 printf("This is the essence of mechanism-policy separation.\n");
 printf("======================================================\n");

 return 0;
}

/*
 * Operating System Design: Implementation Language Portability
 * 
 * This demonstrates why C (and high-level languages) are preferred
 * over assembly for OS development - PORTABILITY
 * 
 * The same code can run on different hardware architectures!
 */

import java.util.Arrays;
import java.util.List;

/**
 * Simulates a simple process control block (PCB)
 * This data structure would be part of the OS kernel
 */
class ProcessControlBlock {
 private final int pid;
 private final String name;
 private ProcessState state;
 private int programCounter;
 private int[] registers;
 private int memoryAddress;

 public ProcessControlBlock(int pid, String name) {
 this.pid = pid;
 this.name = name;
 this.state = ProcessState.NEW;
 this.programCounter = 0;
 this.registers = new int[8]; // Simulated CPU registers
 this.memoryAddress = 0;
 }

 // Getters and setters
 public int getPid() { return pid; }
 public String getName() { return name; }
 public ProcessState getState() { return state; }
 public void setState(ProcessState state) { this.state = state; }
 public int getProgramCounter() { return programCounter; }
 public void setProgramCounter(int pc) { this.programCounter = pc; }
 public int[] getRegisters() { return registers; }
 public int getMemoryAddress() { return memoryAddress; }
 public void setMemoryAddress(int addr) { this.memoryAddress = addr; }
}

enum ProcessState {
 NEW, READY, RUNNING, WAITING, TERMINATED
}

/**
 * Simulates a simple memory manager
 * The SAME code works regardless of underlying hardware!
 */
class MemoryManager {
 private final int totalMemory;
 private final int pageSize;

 public MemoryManager(int totalMemoryKB, int pageSizeKB) {
 this.totalMemory = totalMemoryKB;
 this.pageSize = pageSizeKB;
 }

 /**
 * MECHANISM: Allocate memory for a process
 * This code is the SAME whether running on x86, ARM, RISC-V, etc.
 */
 public int allocateMemory(ProcessControlBlock process, int sizeKB) {
 if (sizeKB > totalMemory) {
 System.out.println("[ERROR] Process " + process.getPid() + 
 " requests more memory than available");
 return -1;
 }

 // Simulated memory allocation
 int baseAddress = (int) (Math.random() * (totalMemory - sizeKB));
 process.setMemoryAddress(baseAddress);

 System.out.println("[MEMORY] Process " + process.getPid() + 
 " allocated " + sizeKB + "KB at physical address 0x" + 
 Integer.toHexString(baseAddress));

 return baseAddress;
 }

 /**
 * MECHANISM: Virtual to physical address translation
 * This abstracts hardware differences!
 */
 public int translateVirtualToPhysical(int virtualAddress) {
 // Simplified page table simulation
 int pageNumber = virtualAddress / pageSize;
 int offset = virtualAddress % pageSize;
 int frameNumber = pageNumber % 10; // Simplified

 return (frameNumber * pageSize) + offset;
 }

 public int getTotalMemory() { return totalMemory; }
 public int getPageSize() { return pageSize; }
}

/**
 * Simulates a context switch mechanism
 * In real OS: saves/loads CPU registers
 */
class CPUScheduler {
 private ProcessControlBlock currentProcess;
 private final MemoryManager memoryManager;

 public CPUScheduler(MemoryManager memoryManager) {
 this.memoryManager = memoryManager;
 this.currentProcess = null;
 }

 /**
 * MECHANISM: Context switch
 * This mechanism is the SAME for all scheduling policies!
 */
 public void contextSwitch(ProcessControlBlock newProcess) {
 if (currentProcess != null) {
 // Save current process state
 System.out.println("[CONTEXT SWITCH] Saving state of Process " + 
 currentProcess.getPid());
 currentProcess.setState(ProcessState.READY);
 }

 // Load new process state
 System.out.println("[CONTEXT SWITCH] Loading state of Process " + 
 newProcess.getPid());
 newProcess.setState(ProcessState.RUNNING);

 this.currentProcess = newProcess;
 }

 public ProcessControlBlock getCurrentProcess() {
 return currentProcess;
 }
}

/**
 * Main class demonstrating OS portability
 */
public class OSPortabilityDemo {

 public static void main(String[] args) {
 System.out.println("=====================================================");
 System.out.println("OS Implementation: Portability with High-Level Language");
 System.out.println("=====================================================\n");

 // Create OS components - works on ANY hardware!
 MemoryManager memory = new MemoryManager(4096, 4); // 4MB RAM, 4KB pages
 CPUScheduler scheduler = new CPUScheduler(memory);

 System.out.println("--- Creating Processes ---\n");

 // Create multiple processes
 ProcessControlBlock process1 = new ProcessControlBlock(1, "WebBrowser");
 ProcessControlBlock process2 = new ProcessControlBlock(2, "CodeEditor");
 ProcessControlBlock process3 = new ProcessControlBlock(3, "MediaPlayer");

 // Allocate memory for processes
 memory.allocateMemory(process1, 512); // 512KB
 memory.allocateMemory(process2, 256); // 256KB
 memory.allocateMemory(process3, 1024); // 1MB

 System.out.println("\n--- Demonstrating Context Switch ---\n");

 // Simulate scheduling
 process1.setState(ProcessState.READY);
 process2.setState(ProcessState.READY);
 process3.setState(ProcessState.READY);

 scheduler.contextSwitch(process1);
 System.out.println(" -> " + scheduler.getCurrentProcess().getName() + 
 " is now RUNNING\n");

 scheduler.contextSwitch(process2);
 System.out.println(" -> " + scheduler.getCurrentProcess().getName() + 
 " is now RUNNING\n");

 scheduler.contextSwitch(process3);
 System.out.println(" -> " + scheduler.getCurrentProcess().getName() + 
 " is now RUNNING\n");

 System.out.println("=====================================================");
 System.out.println("KEY INSIGHTS:");
 System.out.println("=====================================================");
 System.out.println("1. Same Java code runs on x86, ARM, RISC-V, etc.");
 System.out.println("2. Hardware details are abstracted by the OS");
 System.out.println("3. OS components (Memory Manager, Scheduler) are");
 System.out.println(" written in high-level language for portability");
 System.out.println("4. This is why UNIX was rewritten in C in 1973!");
 System.out.println(" (Same reason Linux, Windows kernels use C)");
 System.out.println("=====================================================");
 }
}
